            ProvisioningParameter adminLogin =
                new(nameof(adminLogin), typeof(string))
                {
                    Description = &#34;The administrator username of the MySQL Flexible Server.&#34;
                };
            infra.Add(adminLogin);

            ProvisioningParameter adminPass =
                new(nameof(adminPass), typeof(string))
                {
                    Description = &#34;The administrator password of the MySQL Flexible Server.&#34;,
                    IsSecure = true
                };
            infra.Add(adminPass);

            MySqlFlexibleServer server =
                new(nameof(server), MySqlFlexibleServer.ResourceVersions.V2024_12_30)
                {
                    Sku = new MySqlFlexibleServerSku
                    {
                        Name = &#34;Standard_D2ds_v4&#34;,
                        Tier = MySqlFlexibleServerSkuTier.GeneralPurpose
                    },
                    AdministratorLogin = adminLogin,
                    AdministratorLoginPassword = adminPass,
                    Version = MySqlFlexibleServerVersion.Ver8021,
                    CreateMode = MySqlFlexibleServerCreateMode.Default,
                    Storage = new MySqlFlexibleServerStorage
                    {
                        StorageSizeInGB = 20
                    },
                    Backup = new MySqlFlexibleServerBackupProperties
                    {
                        BackupRetentionDays = 7,
                        GeoRedundantBackup = MySqlFlexibleServerEnableStatusEnum.Disabled
                    },
                    HighAvailability = new MySqlFlexibleServerHighAvailability
                    {
                        Mode = MySqlFlexibleServerHighAvailabilityMode.Disabled
                    }
                };
            infra.Add(server);

            MySqlFlexibleServerDatabase database =
                new(nameof(database), MySqlFlexibleServer.ResourceVersions.V2024_12_30)
                {
                    Parent = server,
                    Name = &#34;myDatabase&#34;,
                    Charset = &#34;utf8mb4&#34;,
                    Collation = &#34;utf8mb4_unicode_ci&#34;
                };
            infra.Add(database);
            #endregion
        }
    }
}
```

2. **Add the snippet placeholder** in `sdk/mysql/Azure.Provisioning.MySql/README.md` under the `## Examples` section heading, replacing the manually-written code block with:

````
```C# Snippet:MySqlFlexibleServerBasic
```
````

The `Update-Snippets.ps1` script will inject the actual code from the test file&#39;s `#region` block into this placeholder.

### Step 3: Verify README structure

The README currently has all required top-level sections present. The following are incomplete and need content as described in Step 1:

1. ✅ Getting started → Install the package — present
2. ✅ Getting started → Prerequisites — present
3. ❌ Getting started → Authenticate the Client — **empty**
4. ❌ Key concepts — **missing resource inventory**
5. ❌ Examples — **empty**
6. ✅ Troubleshooting — present
7. ❌ Next steps — **empty**
8. ✅ Contributing — present

### Step 4: Validate

Run these commands in order:

1. `dotnet build sdk/mysql/Azure.Provisioning.MySql/`
2. `dotnet test sdk/mysql/Azure.Provisioning.MySql/ --filter TestCategory!=Live`
3. `eng/scripts/Update-Snippets.ps1 mysql` — injects snippet code into README placeholder blocks; verify git diff shows README updated correctly
4. `eng/scripts/Export-API.ps1 mysql` — only needed if any public API surface changed; skip if the sample file additions are test-only
5. `dotnet format sdk/mysql/Azure.Provisioning.MySql/`



